example.code:
def normalize(email: str) -> str:
    """Lowercase the local part, strip dots in gmail.com addresses,
    and remove +tags. Idempotent."""

# grounded: docstring "Idempotent."
@given(st.emails())
def test_normalize_idempotent(e):
    assert normalize(normalize(e)) == normalize(e)

@given(st.emails())
def test_normalize_lowercase_only(e):
    # docstring does not say "always all lowercase";
    # this is the agent's assumption.
    assert normalize(e) == normalize(e).lower()
